          {/* Resizer: Left <-> Right */}
          {!isMobile && (
            <div
              className="w-1.5 hover:w-2 bg-slate-200 hover:bg-indigo-400 cursor-col-resize z-20 transition-all flex items-center justify-center group flex-shrink-0"
              onMouseDown={() => setIsDraggingLeft(true)}
            >
               <div className="w-0.5 h-8 bg-slate-400 rounded group-hover:bg-white" />
            </div>
          )}

          {/* Right Panel: Editor & Preview */}
          <div 
            ref={rightPanelRef}
            className={`flex ${isMobile ? 'flex-col gap-4 h-[600px] p-4' : 'flex-row h-full'}`}
            style={{ 
              width: isMobile ? '100%' : `${100 - leftPanelWidth}%`
            }}
          >
             {/* Editor */}
             <div 
               className="h-full flex-shrink-0 relative"
               style={{ 
                 width: isMobile ? '100%' : `${rightPanelSplitRatio}%`,
                 height: isMobile ? '50%' : '100%'
               }}
             >
                <div className={`h-full w-full ${!isMobile ? 'p-2' : ''}`}>
                  {activeLesson && (
                    <CodeEditor
                      tech={activeLesson.tech}
                      initialCode={code}
                      onChange={setCode}
                      onRun={handleRunAndCheck}
                      isCorrect={feedback?.passed}
                    />
                  )}
                </div>
             </div>

             {/* Resizer: Editor <-> Preview */}
             {!isMobile && (
               <div
                  className="w-1.5 hover:w-2 bg-slate-200 hover:bg-indigo-400 cursor-col-resize z-20 transition-all flex items-center justify-center group flex-shrink-0"
                  onMouseDown={() => setIsDraggingRight(true)}
               >
                 <div className="w-0.5 h-8 bg-slate-400 rounded group-hover:bg-white" />
               </div>
             )}

             {/* Preview */}
             <div 
                className="flex-1 h-full relative"
                style={{ 
                    height: isMobile ? '50%' : '100%',
                    pointerEvents: (isDraggingLeft || isDraggingRight) ? 'none' : 'auto' 
                }}
             >
                <div className={`h-full w-full ${!isMobile ? 'p-2' : ''}`}>
                  {activeLesson && <Preview code={code} tech={activeLesson.tech} />}
                </div>
             </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="flex h-screen bg-[#f0f4f9] overflow-hidden">
      <Sidebar />
      <main 
        className={`
          flex-1 flex flex-col min-w-0 transition-all duration-300
          md:${isCollapsed ? 'ml-20' : 'ml-72'}
        `}
      >
         {renderMainContent()}
      </main>

      {/* Overlay for mobile when sidebar is open */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 bg-black/20 z-20 md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}
    </div>
  );
}

import { CourseModule, TechType } from './types';

// アイコンは文字列キーで管理し、UI側でコンポーネントにマッピングします
export const CURRICULUM: CourseModule[] = [
  {
    id: 'html-basics',
    title: 'HTMLをはじめよう',
    icon: 'html',
    color: 'bg-orange-100 text-orange-600',
    lessons: [
      {
        id: 'h1-hello',
        title: 'はじめましての世界',
        description: 'Webページの基本、見出しタグを使ってみましょう。',
        tech: TechType.HTML,
        defaultCode: '<!-- ここにコードを書いてね -->\n',
        task: '<h1>タグを使って、「こんにちは！」と表示させてみましょう。',
        explanation: `
# 見出しタグ <h1> について

Webページを作る旅は、このタグから始まります。
\`<h1>\` は、ページの中で **一番重要な見出し** を表すタグです。新聞で言えば「一面のトップ記事のタイトル」のようなものです。

HTMLでは、このように \`<タグ名>\`（開始タグ）と \`</タグ名>\`（終了タグ）で文字を挟んで意味を持たせます。

## 書き方の例
\`\`\`html
<h1>今日の日記</h1>
\`\`\`

実は見出しには \`<h1>\` から \`<h6>\` まで6段階の大きさがありますが、まずは王様の \`<h1>\` を使いこなしましょう！
        `,
        hints: [
          '<h1> と </h1> で囲むのを忘れていませんか？',
          '文字は「こんにちは！」と正確に入力しましょう。',
          '全て半角英数字でタグを書きます（文字は日本語でOK）。'
        ],
        validate: (code: string) => {
          const cleanCode = code.replace(/\s+/g, ' ').trim();
          if (!cleanCode.includes('<h1>')) {
            return { passed: false, feedback: '<h1>タグが見つかりません。開始タグを書いてみましょう。' };
          }
          if (!cleanCode.includes('</h1>')) {
