                ${activeModuleId === module.id && !isPlayground ? 'bg-[#d3e3fd] text-indigo-900' : 'text-slate-600 hover:bg-slate-200'}
              `}
              title={module.title}
            >
              <div className={`w-5 h-5 flex-shrink-0 ${activeModuleId === module.id ? 'text-indigo-700' : 'text-slate-500'}`}>
