                    <h2 className="text-2xl font-bold text-slate-800 mb-2">
                      {module.title}
                    </h2>
                    <p className="text-slate-400 font-medium mb-6">
                      {module.lessons.length} レッスン
                    </p>

                    <div className="mt-auto flex gap-3">
                         <button
                           className="flex-1 bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-4 rounded-xl flex items-center justify-center gap-2 transition-colors shadow-sm cursor-pointer"
                         >
                           始める <ArrowRightIcon className="w-4 h-4" />
                         </button>
                         <button
                            onClick={(e) => {
                                e.stopPropagation(); // 親のクリックイベントを止める
